var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"1크레딧도 좋습니다……. 제발 도와 주세요. 침식체에게 가족도 집도 전부 잃었습니다…….","JPN":"1クレジットだけでもいいです……どうか助けてください。侵食体に家族も家も全部奪われてしまいました……","ENG":"Spare change? Even 1 Credit is enough... I lost everything to the C.O. My house, my family...","TWN":"哪怕一個金幣也行……求你行行好。我因為侵蝕體而失去家人和房子……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"심하네. 골목마다 전부 노숙자들뿐이야.","JPN":"ひどいな。どの路地もホームレスだらけだよ。","ENG":"This is horrible. All the alleyways are packed with homeless people.","TWN":"這裡情況很糟糕呢。每條巷子裡都有流浪漢。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저런 사람들은 무시해. 구걸하는 사람이 왜 저런 구석진 데 숨어 있겠어?","JPN":"ああいう人たちは無視した方がいいよ。物乞いしなきゃいけない人があんな片隅に隠れてるなんておかしいでしょ。","ENG":"You have to learn to ignore them. Why do you think beggars hide in the shadows?","TWN":"別管他們。你想想看，那些人為什麼要躲在那種角落裡乞討？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저 노숙자들은 미끼야. 멋모르는 사람들을 사각지대로 유인하려는.","JPN":"あのホームレスはエサなの。世間知らずを死角に誘きよせるためのエサ。","ENG":"They're basically bait. To lure in clueless people into the city's blind spots.","TWN":"這些流浪漢只是把陌生人騙進死巷的誘餌。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"유인해서 뭘 하려고?","JPN":"誘きよせてどうするの？","ENG":"What do they do after luring them in?","TWN":"誘餌？騙過去之後要做什麼？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"나도 잘은 모르지.","JPN":"私もよくは知らないけど。","ENG":"Who knows.","TWN":"我也不知道。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"인신매매나 장기밀매를 한다는 소문도 있고. 운이 좋으면 가진 것만 털리고 끝나겠지만.","JPN":"人身売買とか臓器の密売をしてるって噂もある。運が良ければ金目の物を巻き上げられるだけで済むだろうけどね。","ENG":"But there are rumors of human and organ trafficking. But if you're lucky, it'll just cost you your possessions.","TWN":"聽說會有人口販子和買賣器官的。運氣好的話，可能只會把你洗劫一空。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그게 정말이야……?","JPN":"それ、本当……？","ENG":"Are you serious...?","TWN":"你是認真的嗎……？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그렇다니까. 이 도시에는 돈만 벌 수 있으면 뭐든 하려는 인간들이 잔뜩 있거든.","JPN":"そうなんだって。この街にはお金さえ稼げれば何でもやるって人間が掃いて捨てるほどいるんだよ。","ENG":"Yeah. This city is riddled with people who'll do anything for money.","TWN":"嗯嗯，這座城市裡有很多為了錢什麼都做得出來的人。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"경호하러 따라와 준 사람에게 이런 말은 실례려나. 조금 잘난 척해 버렸네.","JPN":"警護でついて来てくれた人にこんな言葉は失礼かな？　ちょっと偉ぶっちゃった。","ENG":"Guess it may sound like I'm showing off. Sorry for saying this to you.","TWN":"你們送我過來，我還說這些有的沒的，真是不好意思。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저기 회색 빌딩 보이지? 저 건물 53층이야.","JPN":"あそこに灰色のビルが見えるでしょ？　あのビルの53階なんだ。","ENG":"Do you see that gray building over there? It's on the 53rd floor.","TWN":"有看到那棟灰色的大樓嗎？就在那棟大樓的53樓。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"건물들이 전부 엄청 높네. 그라운드 원보다 더 심해.","JPN":"超高層ビルばっかりだね。グラウンド・ワンよりひどい。","ENG":"These buildings are really tall. Taller than the ones back at Ground One.","TWN":"這裡的樓都好高，比在G1的大樓還高好多……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"도시는 작은데 사람이 몰려서 그래. 그래서 땅값도 어마어마해.","JPN":"街は小さいのに人が集中しすぎてるからね。それで地価もめちゃくちゃ高いのよ。","ENG":"It's because the city's small but crowded. That's why the real estate price here is out of this world.","TWN":"因為這座城市不大，人口也密集，所以地價也非常高。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"샤레이드에서 부지를 마음대로 살 수 있는 건 알파트릭스 정도일걸?","JPN":"シャレードで欲しい敷地を買えるのはアルファトリックスぐらいなんじゃないかな。","ENG":"The only ones who can afford to freely buy real estate in Charade are probably Alphatrix.","TWN":"在查雷德，應該只有像阿爾法崔克斯那種公司，才有財力可以買地吧？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 정도야…?","JPN":"そんなに……？","ENG":"Is it that much...?","TWN":"那麼誇張嗎……？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"응. 그래서 또 반대로 돈만 있으면 뭐든지 할 수 있는 게 이 도시야.","JPN":"うん。逆に言えばこの街ではお金さえあれば何でもできるってことなの。","ENG":"Yup. But on the flipside, you can do almost anything if you just have enough money.","TWN":"嗯，所以反過來說，在這座城市裡只要有錢就什麼都能做。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님 제안을 받아들인 것도 그래서야? 돈 때문에?","JPN":"社長の提案を受け入れたのもそれで？　お金のために？","ENG":"Is that why you accepted Boss's offer? Because of the money?","TWN":"你之所以接受老闆的提議也是因為這個嗎？因為錢？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};